insert into autor (nome, biografia) values('Ali Hazelwood', 'Ali Hazelwood é uma autora norte-americana. Ela escreve principalmente romances contemporâneos, com foco em narrativas de amor e relacionamentos. Suas obras são conhecidas por apresentar personagens autênticos e envolventes, explorando temas como crescimento pessoal, resiliência e a complexidade das emoções humanas.');
insert into autor (nome, biografia) values('AUgusto Cury', 'Colleen Hoover é uma escritora norte-americana que escreve principalmente romances nos gêneros romântico e ficção para jovens adultos. Muitos de seus trabalhos foram autopublicados antes de serem adquiridos por uma editora.Augusto Cury é um renomado psiquiatra, psicoterapeuta, cientista e escritor brasileiro. Ele é autor de diversos best-sellers que exploram temas relacionados à psicologia, autoajuda e desenvolvimento pessoal. Cury é conhecido por sua abordagem inovadora no estudo da mente humana e suas obras oferecem insights valiosos sobre como lidar com questões emocionais, desenvolver a inteligência emocional e alcançar uma vida mais plena e equilibrada.');
